section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/competitive-intelligence.json",
  "title": "Competitive Intelligence",
  "type": "object",
  "required": [
    "artefact_id",
    "cycle",
    "competitors",
    "deltas",
    "themes",
    "implications",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "cycle": {
      "type": "string",
      "description": "ISO quarter (2026Q2)",
      "minLength": 1
    },
    "competitors": {
      "type": "array",
      "description": "monitored players",
      "minItems": 1
    },
    "deltas": {
      "type": "array",
      "description": "{competitor, field, before, after, source, observed_at}",
      "minItems": 1
    },
    "themes": {
      "type": "array",
      "description": "thematic groupings of deltas",
      "minItems": 1
    },
    "implications": {
      "type": "array",
      "description": "{theme, suggested_action}",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
